/**
 * Questions loader — fetches pre-generated JSON problem files from public/questions/.
 *
 * Problem files are generated by AI (Claude Code / Claude agent) and saved as JSON.
 * The frontend only reads these files; no network/API calls to AI are made at runtime.
 *
 * Directory structure (under public/questions/):
 *   toefl/reading/complete-words/      *.json
 *   toefl/reading/daily-life/          *.json
 *   toefl/reading/academic/            *.json
 *   toefl/writing/build-sentence/      *.json
 *   toefl/writing/email/               *.json
 *   toefl/writing/discussion/          *.json
 *   toefl/speaking/listen-repeat/      *.json
 *   toefl/speaking/interview/          *.json
 *   toeic/part5/                       *.json
 *   toeic/part6/                       *.json
 *   toeic/part7/                       *.json
 *
 * Each directory has an index.json listing available files:
 *   { "files": ["001.json", "002.json", ...] }
 */

export interface QuestionIndex {
  files: string[];
}

export interface LoadedQuestion<T> {
  data: T;
  file: string;
}

export interface QuestionFileEntry {
  file: string;
  number: number;
}

export async function fetchQuestionIndex(
  taskPath: string,
): Promise<QuestionIndex> {
  const res = await fetch(`/questions/${taskPath}/index.json`);
  if (!res.ok)
    throw new Error(`No questions found for ${taskPath}. Generate some first!`);
  return res.json();
}

export async function fetchRandomQuestion<T>(taskPath: string): Promise<T> {
  const loaded = await fetchRandomQuestionWithMeta<T>(taskPath);
  return loaded.data;
}

export async function listQuestionFiles(
  taskPath: string,
): Promise<QuestionFileEntry[]> {
  const index = await fetchQuestionIndex(taskPath);
  return index.files
    .map((file) => {
      const basename = file.replace(/\.[^.]+$/, "");
      if (!/^\d+$/.test(basename)) {
        throw new Error(
          `Question file "${file}" in ${taskPath} must use numeric filename like 001.json.`,
        );
      }
      return {
        file,
        number: Number.parseInt(basename, 10),
      };
    })
    .sort((a, b) => a.number - b.number || a.file.localeCompare(b.file));
}

export async function fetchQuestionByFileWithMeta<T>(
  taskPath: string,
  file: string,
): Promise<LoadedQuestion<T>> {
  const res = await fetch(`/questions/${taskPath}/${file}`);
  if (!res.ok) throw new Error(`Failed to load question file: ${file}`);
  const data = (await res.json()) as T;
  return { data, file };
}

export async function fetchQuestionByNumberWithMeta<T>(
  taskPath: string,
  questionNumber: number,
): Promise<LoadedQuestion<T>> {
  const files = await listQuestionFiles(taskPath);
  const selected = files.find((item) => item.number === questionNumber);
  if (!selected) {
    throw new Error(
      `Question ${questionNumber} not found in ${taskPath}. Generate or register it first.`,
    );
  }
  return fetchQuestionByFileWithMeta<T>(taskPath, selected.file);
}

export async function fetchRandomQuestionWithMeta<T>(
  taskPath: string,
): Promise<LoadedQuestion<T>> {
  const files = await listQuestionFiles(taskPath);
  if (files.length === 0) {
    throw new Error(`No question files in ${taskPath}. Generate some first!`);
  }
  const selected = files[Math.floor(Math.random() * files.length)];
  return fetchQuestionByFileWithMeta<T>(taskPath, selected.file);
}

export async function fetchAllQuestions<T>(taskPath: string): Promise<T[]> {
  const index = await fetchQuestionIndex(taskPath);
  const results = await Promise.all(
    index.files.map(async (file) => {
      const res = await fetch(`/questions/${taskPath}/${file}`);
      if (!res.ok) throw new Error(`Failed to load: ${file}`);
      return res.json() as Promise<T>;
    }),
  );
  return results;
}

export interface SaveAnswerPayload {
  taskId: string;
  problemId: string;
  response: string;
  question?: unknown;
}

interface SaveAnswerResponse {
  answerId: string;
}

export interface AnswerEntry {
  answerId: string;
  taskId: string;
  problemId: string;
  response: string;
  date: string;
}

const DRAFT_KEY_PREFIX = "answer-draft:";
const ANSWERS_STORAGE_KEY = "answer-history";

export function buildProblemId(
  taskId: string,
  sourceFile: string,
  subQuestionId?: string,
) {
  const fileId = sourceFile.replace(/\.json$/i, "");
  if (subQuestionId) {
    return `${taskId}/${fileId}#${subQuestionId}`;
  }
  return `${taskId}/${fileId}`;
}

export function buildDraftKey(problemId: string) {
  return `${DRAFT_KEY_PREFIX}${problemId}`;
}

export function loadDraft(problemId: string) {
  const value = localStorage.getItem(buildDraftKey(problemId));
  return value ?? "";
}

export function saveDraft(problemId: string, text: string) {
  const key = buildDraftKey(problemId);
  if (text.trim().length === 0) {
    localStorage.removeItem(key);
    return;
  }
  localStorage.setItem(key, text);
}

export function clearDraft(problemId: string) {
  localStorage.removeItem(buildDraftKey(problemId));
}

function readAnswerHistory(): AnswerEntry[] {
  try {
    const raw = localStorage.getItem(ANSWERS_STORAGE_KEY);
    return raw ? (JSON.parse(raw) as AnswerEntry[]) : [];
  } catch {
    return [];
  }
}

function writeAnswerHistory(entries: AnswerEntry[]) {
  localStorage.setItem(ANSWERS_STORAGE_KEY, JSON.stringify(entries));
}

export async function saveAnswerSubmission(payload: SaveAnswerPayload) {
  const entries = readAnswerHistory();
  const answerId = `ans-${Date.now()}`;
  const entry: AnswerEntry = {
    answerId,
    taskId: payload.taskId,
    problemId: payload.problemId,
    response: payload.response,
    date: new Date().toISOString(),
  };
  entries.push(entry);
  writeAnswerHistory(entries);
  return { answerId } as SaveAnswerResponse;
}

export function getAllAnswers(): AnswerEntry[] {
  return readAnswerHistory().slice().reverse();
}

export function buildGradingMessage(problemId: string, answerId: string) {
  return `I completed problem ${problemId}. My answer ID is ${answerId}. Please grade it.`;
}

export async function copyText(text: string) {
  if (typeof navigator.clipboard?.writeText !== "function") {
    return false;
  }
  await navigator.clipboard.writeText(text);
  return true;
}

export async function transcribeAudio(
  audio: Blob,
  url: string,
  signal?: AbortSignal,
): Promise<string> {
  const formData = new FormData();
  formData.append("audio", audio, "recording.webm");

  const response = await fetch(url, {
    method: "POST",
    body: formData,
    signal,
  });

  if (!response.ok) {
    const body = (await response.json().catch(() => ({}))) as {
      error?: string;
    };
    throw new Error(
      body.error ?? `Transcription request failed (${response.status})`,
    );
  }

  const body = (await response.json()) as { text?: string };
  return body.text ?? "";
}

import { useCallback } from "react";

export type TaskId =
  | "toefl/reading/complete-words"
  | "toefl/reading/daily-life"
  | "toefl/reading/academic"
  | "toefl/listening/conversation"
  | "toefl/listening/lecture"
  | "toefl/listening/response"
  | "toefl/listening/announcement"
  | "toefl/writing/build-sentence"
  | "toefl/writing/email"
  | "toefl/writing/discussion"
  | "toefl/speaking/listen-repeat"
  | "toefl/speaking/interview"
  | "toeic/part2"
  | "toeic/part3"
  | "toeic/part4"
  | "toeic/part5"
  | "toeic/part6"
  | "toeic/part7"
  | "shadowing";

export interface ScoreEntry {
  taskId: TaskId;
  date: string;
  correct: number;
  total: number;
  pct: number;
  elapsedSeconds?: number;
  questionFile?: string;
}

const STORAGE_KEY = "score-history";

function readScores(): ScoreEntry[] {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    return raw ? (JSON.parse(raw) as ScoreEntry[]) : [];
  } catch {
    return [];
  }
}

function writeScores(entries: ScoreEntry[]) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(entries));
}

export function useScoreHistory() {
  const saveScore = useCallback(
    async (
      taskId: TaskId,
      correct: number,
      total: number,
      elapsedSeconds = 0,
      questionFile?: string,
    ) => {
      if (total === 0) return;
      const entry: ScoreEntry = {
        taskId,
        date: new Date().toISOString(),
        correct,
        total,
        pct: Math.round((correct / total) * 100),
        elapsedSeconds: Math.max(0, Math.floor(elapsedSeconds)),
      };
      if (questionFile) {
        entry.questionFile = questionFile;
      }
      const entries = readScores();
      entries.push(entry);
      writeScores(entries);
    },
    [],
  );

  const getAll = useCallback(async (): Promise<ScoreEntry[]> => {
    return readScores();
  }, []);

  const clearAll = useCallback(async () => {
    localStorage.removeItem(STORAGE_KEY);
  }, []);

  return { saveScore, getAll, clearAll };
}

import { useState, useCallback } from "react";
import {
  fetchQuestionByFileWithMeta,
  fetchQuestionByNumberWithMeta,
  fetchRandomQuestionWithMeta,
} from "../lib/questions";

/**
 * Hook that loads a random pre-generated question file for a given task.
 * Call `load()` to fetch a new random question from public/questions/<taskPath>/.
 */
export function useQuestion<T>(taskPath: string) {
  const [data, setData] = useState<T | null>(null);
  const [file, setFile] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const result = await fetchRandomQuestionWithMeta<T>(taskPath);
      setData(result.data);
      setFile(result.file);
    } catch (e) {
      setData(null);
      setFile(null);
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setLoading(false);
    }
  }, [taskPath]);

  const loadByFile = useCallback(
    async (questionFile: string) => {
      setLoading(true);
      setError(null);
      try {
        const result = await fetchQuestionByFileWithMeta<T>(
          taskPath,
          questionFile,
        );
        setData(result.data);
        setFile(result.file);
      } catch (e) {
        setData(null);
        setFile(null);
        setError(e instanceof Error ? e.message : String(e));
      } finally {
        setLoading(false);
      }
    },
    [taskPath],
  );

  const loadByQuestionNumber = useCallback(
    async (questionNumber: number) => {
      setLoading(true);
      setError(null);
      try {
        const result = await fetchQuestionByNumberWithMeta<T>(
          taskPath,
          questionNumber,
        );
        setData(result.data);
        setFile(result.file);
      } catch (e) {
        setData(null);
        setFile(null);
        setError(e instanceof Error ? e.message : String(e));
      } finally {
        setLoading(false);
      }
    },
    [taskPath],
  );

  return { data, file, loading, error, load, loadByFile, loadByQuestionNumber };
}

import { useState, useEffect, useRef, useCallback } from "react";

export function useTimer(initialSeconds: number, onExpire?: () => void) {
  const [seconds, setSeconds] = useState(initialSeconds);
  const [running, setRunning] = useState(false);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const onExpireRef = useRef(onExpire);
  useEffect(() => {
    onExpireRef.current = onExpire;
  }, [onExpire]);

  const clear = useCallback(() => {
    if (intervalRef.current) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
  }, []);

  const start = useCallback(() => {
    setRunning(true);
  }, []);

  const stop = useCallback(() => {
    setRunning(false);
    clear();
  }, [clear]);

  const reset = useCallback(() => {
    stop();
    setSeconds(initialSeconds);
  }, [stop, initialSeconds]);

  useEffect(() => {
    if (!running) return;
    intervalRef.current = setInterval(() => {
      setSeconds((s) => {
        if (s <= 1) {
          clear();
          setRunning(false);
          onExpireRef.current?.();
          return 0;
        }
        return s - 1;
      });
    }, 1000);
    return clear;
  }, [running, clear]);

  const minutes = Math.floor(seconds / 60);
  const secs = seconds % 60;
  const display = `${String(minutes).padStart(2, "0")}:${String(secs).padStart(2, "0")}`;
  const isWarning = seconds <= 60 && seconds > 0;
  const isExpired = seconds === 0;

  return {
    seconds,
    display,
    isWarning,
    isExpired,
    running,
    start,
    stop,
    reset,
  };
}

import { useCallback, useEffect, useRef, useState } from "react";
import { formatSecondsAsMmSs } from "../lib/time";

export function useElapsedTimer() {
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const [running, setRunning] = useState(false);

  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const startedAtRef = useRef<number | null>(null);
  const baseSecondsRef = useRef(0);

  const clear = useCallback(() => {
    if (!intervalRef.current) return;
    clearInterval(intervalRef.current);
    intervalRef.current = null;
  }, []);

  const sync = useCallback(() => {
    if (startedAtRef.current == null) return baseSecondsRef.current;
    const total =
      baseSecondsRef.current +
      Math.floor((Date.now() - startedAtRef.current) / 1000);
    setElapsedSeconds(total);
    return total;
  }, []);

  const start = useCallback(() => {
    if (startedAtRef.current != null) return;
    startedAtRef.current = Date.now();
    setRunning(true);
    setElapsedSeconds(baseSecondsRef.current);
  }, []);

  const stop = useCallback(() => {
    if (startedAtRef.current == null) return baseSecondsRef.current;
    const total =
      baseSecondsRef.current +
      Math.floor((Date.now() - startedAtRef.current) / 1000);
    baseSecondsRef.current = total;
    startedAtRef.current = null;
    setElapsedSeconds(total);
    setRunning(false);
    clear();
    return total;
  }, [clear]);

  const reset = useCallback(() => {
    startedAtRef.current = null;
    baseSecondsRef.current = 0;
    setElapsedSeconds(0);
    setRunning(false);
    clear();
  }, [clear]);

  useEffect(() => {
    if (!running) return;
    intervalRef.current = setInterval(sync, 1000);
    sync();
    return clear;
  }, [running, sync, clear]);

  useEffect(() => clear, [clear]);

  return {
    elapsedSeconds,
    display: formatSecondsAsMmSs(elapsedSeconds),
    running,
    start,
    stop,
    reset,
  };
}

